import collections
from typing import List

class TrieNode:
    def __init__(self):
        self.children: dict[str, TrieNode] = {}
        self.deleted = False

class Solution:
    def deleteDuplicateFolder(self, paths: List[List[str]]) -> List[List[str]]:
        ans = []
        root = TrieNode()
        subtreeToNodes: dict[str, List[TrieNode]] = collections.defaultdict(list)

        # Construct the Trie
        for path in sorted(paths):
            node = root
            for s in path:
                node = node.children.setdefault(s, TrieNode())

        # For each subtree, fill in the {subtree encoding: [root]} hash table
        def buildSubtreeToRoots(node: TrieNode) -> str:
            subtree = '(' + ''.join(s + buildSubtreeToRoots(node.children[s])
                                    for s in node.children) + ')'
            if subtree != '()':
                subtreeToNodes[subtree].append(node)
            return subtree

        buildSubtreeToRoots(root)

        # Mark nodes that should be deleted
        for nodes in subtreeToNodes.values():
            if len(nodes) > 1:
                for node in nodes:
                    node.deleted = True

        # Construct the answer array for nodes that haven't been deleted
        def constructPath(node: TrieNode, path: List[str]) -> None:
            for s, child in node.children.items():
                if not child.deleted:
                    constructPath(child, path + [s])
            if path:
                ans.append(path)

        constructPath(root, [])
        return ans
```

This solution constructs a Trie from the given paths, identifies duplicate subtrees, marks them for deletion, and then constructs the remaining paths that are not marked for deletion. The use of a Trie allows efficient representation and comparison of the directory structure, while the hashing mechanism helps in identifying duplicate subtrees.
